//vip.opstream-short.com/20251117/32241_dcdd0d62/index.m3u8"},{"name":"77","slug":"77","filename":"Ôi! Tướng Quân Của Em - Tập 77---2025","link_embed":"https://vip.opstream-short.com/share/3314dfc68a97404aeecc86a670e50766","link_m3u8":"https://vip.opstream-short.com/20251117/32242_3314dfc6/index.m3u8"},{"name":"78","slug":"78","filename":"Ôi! Tướng Quân Của Em - Tập 78---2025","link_embed":"https://vip.opstream-short.com/share/7501788417c5c49436d7aba3c0695833","link_m3u8":"https://vip.opstream-short.com/20251117/32243_75017884/index.m3u8"}]}],"time":"2 phút/tập","description":"<p>Thời cổ đại, hai người yêu nhau bị mắc kẹt trong chu kỳ tái sinh bi thảm vì lời nguyền của hoàng đế. Kiếp thứ nhất, nữ chính chết để cứu vị tướng quân yêu dấu. Kiếp thứ hai, họ gặp nhau và yêu lại từ đầu, nhưng cô lại chết để bảo vệ anh. Kiếp thứ ba, tướng quân cứu cô ngay lần đầu gặp mặt, cô theo đuổi anh một cách nhiệt tình. Họ yêu nhau, nhưng tướng quân kiệt sức để bảo vệ cô đến mức tóc bạc trong một đêm. May mắn thay, tình yêu của họ sinh ra một đứa con cứu được anh, và gia đình ba người sống hạnh phúc mãi mãi.</p>","tmdb":{"type":"tv","id":"","season":1,"vote_average":0,"vote_count":0},"modified":"2025-11-24T10:21:41.000Z"},{"id":"6923cf5b4122f0d6501435d5","_id":"6923cf5b4122f0d6501435d5","title":"Sau Khi Cưới Chớp Nhoáng, Danh Tính Của Chồng Vệ Sĩ Liên Tục Bị Lộ","origin_name":"闪婚后保镖老公马甲又掉了","slug":"sau-khi-cuoi-chop-nhoang-danh-tinh-cua-chong-ve-si-lien-tuc-bi-lo-short-drama","thumb":"/uploads/movies/sau-khi-cuoi-chop-nhoang,-danh-tinh-cua-chong-ve-si-lien-tuc-bi-lo-short-drama-thumb.jpg","poster":"","year":2025,"type":"series","genre":[{"id":"68f786a9f998955ed60add6c","name":"Short Drama","slug":"short-drama"}],"country":[{"id":"62093063196e9f4ab6b448b8","name":"Trung Quốc","slug":"trung-quoc"}],"lang_key":"Vietsub","episode_current":"Hoàn Tất (90/90)","quality":"HD","is_4k":false,"is_exclusive":false,"status":"","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"ser